import{_ as t,c as i,o as e,a1 as o}from"./chunks/framework.DILC4Csi.js";const b=JSON.parse('{"title":"Obsidian連携：プランを自動保存 | plannotator","description":"plannotatorのObsidian連携設定方法を学びます。承認したプランをvaultに自動保存し、frontmatterとタグの自動生成機能、カスタム保存パスの設定をマスターします。","frontmatter":{"title":"Obsidian連携：プランを自動保存 | plannotator","sidebarTitle":"Obsidianへ自動保存","subtitle":"Obsidian連携：プランを自動保存 | plannotator","description":"plannotatorのObsidian連携設定方法を学びます。承認したプランをvaultに自動保存し、frontmatterとタグの自動生成機能、カスタム保存パスの設定をマスターします。","tags":["plannotator","integration","obsidian","advanced"],"prerequisite":["start-getting-started"],"order":2},"headers":[],"relativePath":"ja/backnotprop/plannotator/advanced/obsidian-integration/index.md","filePath":"ja/backnotprop/plannotator/advanced/obsidian-integration/index.md"}'),n={name:"ja/backnotprop/plannotator/advanced/obsidian-integration/index.md"};function r(l,a,s,d,c,h){return e(),i("div",null,[...a[0]||(a[0]=[o(`<h1 id="obsidian連携-プランをノートライブラリに自動保存" tabindex="-1">Obsidian連携：プランをノートライブラリに自動保存 <a class="header-anchor" href="#obsidian連携-プランをノートライブラリに自動保存" aria-label="Permalink to &quot;Obsidian連携：プランをノートライブラリに自動保存&quot;">​</a></h1><h2 id="この章で学べること" tabindex="-1">この章で学べること <a class="header-anchor" href="#この章で学べること" aria-label="Permalink to &quot;この章で学べること&quot;">​</a></h2><ul><li>承認または却下したプランをObsidian vaultに自動保存する</li><li>frontmatterとタグの生成メカニズムを理解する</li><li>保存パスとフォルダをカスタマイズする</li><li>backlinkを活用してナレッジグラフを構築する</li></ul><h2 id="現在の課題" tabindex="-1">現在の課題 <a class="header-anchor" href="#現在の課題" aria-label="Permalink to &quot;現在の課題&quot;">​</a></h2><p>PlannotatorでAI生成プランをレビューし、承認した後、それらのプランは「消えて」しまいます。価値あるプランをObsidianに保存して、後から振り返ったり検索したりしたいのですが、手動でコピー＆ペーストするのは面倒で、フォーマットも崩れてしまいます。</p><h2 id="こんなときに使う" tabindex="-1">こんなときに使う <a class="header-anchor" href="#こんなときに使う" aria-label="Permalink to &quot;こんなときに使う&quot;">​</a></h2><ul><li>Obsidianをナレッジ管理ツールとして使用している</li><li>AI生成の実装プランを長期保存して振り返りたい</li><li>Obsidianのgraph viewとタグシステムでプランを整理したい</li></ul><h2 id="コアコンセプト" tabindex="-1">コアコンセプト <a class="header-anchor" href="#コアコンセプト" aria-label="Permalink to &quot;コアコンセプト&quot;">​</a></h2><p>PlannotatorのObsidian連携機能は、プランを承認または却下したときに、自動的にプラン内容をObsidian vaultに保存します。システムは以下を行います：</p><ol><li><strong>vaultsの検出</strong>：Obsidian設定ファイルからすべてのvaultを自動読み取り</li><li><strong>frontmatterの生成</strong>：作成日時、ソース、タグを含む</li><li><strong>タグの抽出</strong>：プランタイトルとコードブロック言語から自動抽出</li><li><strong>backlinkの追加</strong>：<code>[[Plannotator Plans]]</code>リンクを挿入し、ナレッジグラフ構築を支援</li></ol><div class="info custom-block"><p class="custom-block-title">Obsidianとは？</p><p>Obsidianはローカルファースト設計の双方向リンクノートアプリです。Markdownフォーマットをサポートし、グラフビューでノート間の関係を可視化できます。</p></div><h2 id="🎒-始める前の準備" tabindex="-1">🎒 始める前の準備 <a class="header-anchor" href="#🎒-始める前の準備" aria-label="Permalink to &quot;🎒 始める前の準備&quot;">​</a></h2><p>Obsidianがインストールされ、設定済みであることを確認してください。Plannotatorはシステム内のvaultsを自動検出しますが、この機能を使用するには少なくとも1つのvaultが必要です。</p><h2 id="ステップバイステップ" tabindex="-1">ステップバイステップ <a class="header-anchor" href="#ステップバイステップ" aria-label="Permalink to &quot;ステップバイステップ&quot;">​</a></h2><h3 id="ステップ1-設定パネルを開く" tabindex="-1">ステップ1：設定パネルを開く <a class="header-anchor" href="#ステップ1-設定パネルを開く" aria-label="Permalink to &quot;ステップ1：設定パネルを開く&quot;">​</a></h3><p>Plannotatorインターフェースで、右上の歯車アイコンをクリックして設定パネルを開きます。</p><p>設定ダイアログが表示され、複数の設定オプションが含まれています。</p><h3 id="ステップ2-obsidian連携を有効化" tabindex="-1">ステップ2：Obsidian連携を有効化 <a class="header-anchor" href="#ステップ2-obsidian連携を有効化" aria-label="Permalink to &quot;ステップ2：Obsidian連携を有効化&quot;">​</a></h3><p>設定パネルで「Obsidian Integration」セクションを見つけ、スイッチをクリックして機能を有効にします。</p><p>有効にすると、Plannotatorがシステム内のObsidian vaultsを自動検出します。</p><p>ドロップダウンメニューに検出されたvaults（例：<code>My Vault</code>、<code>Work Notes</code>）が表示されます。</p><h3 id="ステップ3-vaultとフォルダを選択" tabindex="-1">ステップ3：vaultとフォルダを選択 <a class="header-anchor" href="#ステップ3-vaultとフォルダを選択" aria-label="Permalink to &quot;ステップ3：vaultとフォルダを選択&quot;">​</a></h3><p>ドロップダウンメニューからプランを保存したいvaultを選択します。vaultが検出されない場合は：</p><ol><li>「Custom path...」オプションを選択</li><li>テキストボックスにvaultの完全パスを入力</li></ol><p>次に「Folder」フィールドで保存フォルダ名を設定します（デフォルトは<code>plannotator</code>）。</p><p>下部のプレビューパスに、プランが保存される場所が表示されます。</p><h3 id="ステップ4-プランを承認または却下" tabindex="-1">ステップ4：プランを承認または却下 <a class="header-anchor" href="#ステップ4-プランを承認または却下" aria-label="Permalink to &quot;ステップ4：プランを承認または却下&quot;">​</a></h3><p>設定完了後、通常通りAI生成プランをレビューします。「Approve」または「Send Feedback」をクリックすると、プランが設定したvaultに自動保存されます。</p><p>Obsidianに新しいファイルが作成され、ファイル名は<code>Title - Jan 2, 2026 2-30pm.md</code>の形式になります。</p><h3 id="ステップ5-保存されたファイルを確認" tabindex="-1">ステップ5：保存されたファイルを確認 <a class="header-anchor" href="#ステップ5-保存されたファイルを確認" aria-label="Permalink to &quot;ステップ5：保存されたファイルを確認&quot;">​</a></h3><p>Obsidianで保存されたファイルを開くと、以下の内容が表示されます：</p><div class="language-markdown vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">markdown</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">---</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">created</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">2026-01-24T14:30:00.000Z</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">source</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">plannotator</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">tags</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: [</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">plan</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">authentication</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">typescript</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">sql</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">---</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">[[Plannotator Plans]]</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-light-font-weight:bold;--shiki-dark:#79B8FF;--shiki-dark-font-weight:bold;">## Implementation Plan: User Authentication</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">...</span></span></code></pre></div><p>ファイル上部にYAML frontmatterがあり、作成日時、ソース、タグが含まれています。</p><h2 id="チェックポイント-✅" tabindex="-1">チェックポイント ✅ <a class="header-anchor" href="#チェックポイント-✅" aria-label="Permalink to &quot;チェックポイント ✅&quot;">​</a></h2><ul><li>[ ] 設定パネルでObsidian Integrationが有効になっている</li><li>[ ] vaultを選択済み（またはカスタムパスを入力済み）</li><li>[ ] フォルダ名を設定済み</li><li>[ ] プランを承認または却下後、Obsidianに新しいファイルが作成される</li><li>[ ] ファイルにfrontmatterと<code>[[Plannotator Plans]]</code> backlinkが含まれている</li></ul><h2 id="frontmatterとタグの詳細" tabindex="-1">Frontmatterとタグの詳細 <a class="header-anchor" href="#frontmatterとタグの詳細" aria-label="Permalink to &quot;Frontmatterとタグの詳細&quot;">​</a></h2><h3 id="frontmatterの構造" tabindex="-1">Frontmatterの構造 <a class="header-anchor" href="#frontmatterの構造" aria-label="Permalink to &quot;Frontmatterの構造&quot;">​</a></h3><p>保存される各プランには以下のfrontmatterフィールドが含まれます：</p><table tabindex="0"><thead><tr><th>フィールド</th><th>値の例</th><th>説明</th></tr></thead><tbody><tr><td><code>created</code></td><td><code>2026-01-24T14:30:00.000Z</code></td><td>ISO 8601形式の作成タイムスタンプ</td></tr><tr><td><code>source</code></td><td><code>plannotator</code></td><td>固定値、ソースを識別</td></tr><tr><td><code>tags</code></td><td><code>[plan, authentication, typescript]</code></td><td>自動抽出されたタグ配列</td></tr></tbody></table><h3 id="タグ生成ルール" tabindex="-1">タグ生成ルール <a class="header-anchor" href="#タグ生成ルール" aria-label="Permalink to &quot;タグ生成ルール&quot;">​</a></h3><p>Plannotatorは以下のルールでタグを自動抽出します：</p><ol><li><strong>デフォルトタグ</strong>：常に<code>plannotator</code>タグを含む</li><li><strong>プロジェクト名タグ</strong>：gitリポジトリ名またはディレクトリ名から自動抽出</li><li><strong>タイトルキーワード</strong>：最初のH1タイトルから意味のある単語を抽出（一般的なストップワードを除外）</li><li><strong>コード言語タグ</strong>：コードブロックの言語識別子から抽出（例：<code>typescript</code>、<code>sql</code>）。汎用設定言語（<code>json</code>、<code>yaml</code>、<code>markdown</code>など）は自動的にフィルタリングされます。</li></ol><p>ストップワードリスト（タグにならない単語）：</p><ul><li><code>the</code>, <code>and</code>, <code>for</code>, <code>with</code>, <code>this</code>, <code>that</code>, <code>from</code>, <code>into</code></li><li><code>plan</code>, <code>implementation</code>, <code>overview</code>, <code>phase</code>, <code>step</code>, <code>steps</code></li></ul><p>タグ数の制限：最大7個、抽出順に並びます。</p><h3 id="ファイル名の形式" tabindex="-1">ファイル名の形式 <a class="header-anchor" href="#ファイル名の形式" aria-label="Permalink to &quot;ファイル名の形式&quot;">​</a></h3><p>ファイル名は読みやすい形式を採用：<code>Title - Jan 2, 2026 2-30pm.md</code></p><table tabindex="0"><thead><tr><th>部分</th><th>例</th><th>説明</th></tr></thead><tbody><tr><td>タイトル</td><td><code>User Authentication</code></td><td>H1から抽出、50文字制限</td></tr><tr><td>日付</td><td><code>Jan 2, 2026</code></td><td>現在の日付</td></tr><tr><td>時刻</td><td><code>2-30pm</code></td><td>現在の時刻（12時間制）</td></tr></tbody></table><h3 id="backlinkメカニズム" tabindex="-1">Backlinkメカニズム <a class="header-anchor" href="#backlinkメカニズム" aria-label="Permalink to &quot;Backlinkメカニズム&quot;">​</a></h3><p>各プランファイルの末尾に<code>[[Plannotator Plans]]</code>リンクが挿入されます。このbacklinkの役割：</p><ul><li><strong>ナレッジグラフ接続</strong>：Obsidianのgraph viewで、すべてのプランが同じノードに接続される</li><li><strong>クイックナビゲーション</strong>：<code>[[Plannotator Plans]]</code>をクリックすると、すべての保存プランをまとめたインデックスページを作成できる</li><li><strong>双方向リンク</strong>：インデックスページでバックリンクを使用してすべてのプランを表示</li></ul><h2 id="クロスプラットフォームサポート" tabindex="-1">クロスプラットフォームサポート <a class="header-anchor" href="#クロスプラットフォームサポート" aria-label="Permalink to &quot;クロスプラットフォームサポート&quot;">​</a></h2><p>Plannotatorは異なるOSのObsidian設定ファイルの場所を自動検出します：</p><table tabindex="0"><thead><tr><th>OS</th><th>設定ファイルパス</th></tr></thead><tbody><tr><td>macOS</td><td><code>~/Library/Application Support/obsidian/obsidian.json</code></td></tr><tr><td>Windows</td><td><code>%APPDATA%\\obsidian/obsidian.json</code></td></tr><tr><td>Linux</td><td><code>~/.config/obsidian/obsidian.json</code></td></tr></tbody></table><p>自動検出に失敗した場合は、vaultパスを手動で入力できます。</p><h2 id="よくあるトラブル" tabindex="-1">よくあるトラブル <a class="header-anchor" href="#よくあるトラブル" aria-label="Permalink to &quot;よくあるトラブル&quot;">​</a></h2><h3 id="問題1-vaultsが検出されない" tabindex="-1">問題1：vaultsが検出されない <a class="header-anchor" href="#問題1-vaultsが検出されない" aria-label="Permalink to &quot;問題1：vaultsが検出されない&quot;">​</a></h3><p><strong>症状</strong>：ドロップダウンメニューに「Detecting...」と表示されるが結果がない</p><p><strong>原因</strong>：Obsidian設定ファイルが存在しないか、フォーマットが不正</p><p><strong>解決方法</strong>：</p><ol><li>Obsidianがインストールされ、少なくとも一度開いたことを確認</li><li>設定ファイルが存在するか確認（上記の表のパスを参照）</li><li>「Custom path...」でvaultパスを手動入力</li></ol><h3 id="問題2-保存後にファイルが見つからない" tabindex="-1">問題2：保存後にファイルが見つからない <a class="header-anchor" href="#問題2-保存後にファイルが見つからない" aria-label="Permalink to &quot;問題2：保存後にファイルが見つからない&quot;">​</a></h3><p><strong>症状</strong>：プランを承認後、Obsidianに新しいファイルがない</p><p><strong>原因</strong>：vaultパスが間違っているか、Obsidianが更新されていない</p><p><strong>解決方法</strong>：</p><ol><li>設定パネルのプレビューパスが正しいか確認</li><li>Obsidianで「Reload vault」をクリックするか、<code>Cmd+R</code>（macOS）/ <code>Ctrl+R</code>（Windows/Linux）を押す</li><li>正しいvaultを選択しているか確認</li></ol><h3 id="問題3-ファイル名に特殊文字が含まれる" tabindex="-1">問題3：ファイル名に特殊文字が含まれる <a class="header-anchor" href="#問題3-ファイル名に特殊文字が含まれる" aria-label="Permalink to &quot;問題3：ファイル名に特殊文字が含まれる&quot;">​</a></h3><p><strong>症状</strong>：ファイル名に<code>_</code>やその他の置換文字が表示される</p><p><strong>原因</strong>：タイトルにファイルシステムでサポートされない文字（<code>&lt; &gt; : &quot; / \\ | ? *</code>）が含まれている</p><p><strong>解決方法</strong>：これは想定された動作です。Plannotatorはファイルシステムエラーを避けるため、これらの文字を自動的に置換します。</p><h2 id="この章のまとめ" tabindex="-1">この章のまとめ <a class="header-anchor" href="#この章のまとめ" aria-label="Permalink to &quot;この章のまとめ&quot;">​</a></h2><p>Obsidian連携機能により、プランレビューワークフローとナレッジ管理がシームレスに接続されます：</p><ul><li>✅ 承認または却下したプランを自動保存</li><li>✅ タグをスマートに抽出し、後からの検索を容易に</li><li>✅ frontmatterを生成し、メタデータ形式を統一</li><li>✅ backlinkを追加し、ナレッジグラフを構築</li></ul><p>一度設定すれば、毎回のレビューが自動的にアーカイブされ、手動でコピー＆ペーストする必要がなくなります。</p><h2 id="次の章の予告" tabindex="-1">次の章の予告 <a class="header-anchor" href="#次の章の予告" aria-label="Permalink to &quot;次の章の予告&quot;">​</a></h2><blockquote><p>次の章では**<a href="./../bear-integration/">Bear連携</a>**を学びます。</p><p>学べる内容：</p><ul><li>プランをBearノートアプリに保存する方法</li><li>Bear連携とObsidian連携の違い</li><li>x-callback-urlを使用してノートを自動作成</li></ul></blockquote><hr><h2 id="付録-ソースコード参照" tabindex="-1">付録：ソースコード参照 <a class="header-anchor" href="#付録-ソースコード参照" aria-label="Permalink to &quot;付録：ソースコード参照&quot;">​</a></h2><details><summary><strong>クリックしてソースコードの場所を表示</strong></summary><blockquote><p>更新日：2026-01-24</p></blockquote><table tabindex="0"><thead><tr><th>機能</th><th>ファイルパス</th><th>行番号</th></tr></thead><tbody><tr><td>Obsidian vaultsの検出</td><td><a href="https://github.com/backnotprop/plannotator/blob/main/packages/server/integrations.ts#L135-L175" target="_blank" rel="noreferrer"><code>packages/server/integrations.ts</code></a></td><td>135-175</td></tr><tr><td>Obsidianへプラン保存</td><td><a href="https://github.com/backnotprop/plannotator/blob/main/packages/server/integrations.ts#L180-L227" target="_blank" rel="noreferrer"><code>packages/server/integrations.ts</code></a></td><td>180-227</td></tr><tr><td>タグ抽出</td><td><a href="https://github.com/backnotprop/plannotator/blob/main/packages/server/integrations.ts#L34-L74" target="_blank" rel="noreferrer"><code>packages/server/integrations.ts</code></a></td><td>34-74</td></tr><tr><td>frontmatter生成</td><td><a href="https://github.com/backnotprop/plannotator/blob/main/packages/server/integrations.ts#L81-L89" target="_blank" rel="noreferrer"><code>packages/server/integrations.ts</code></a></td><td>81-89</td></tr><tr><td>ファイル名生成</td><td><a href="https://github.com/backnotprop/plannotator/blob/main/packages/server/integrations.ts#L111-L127" target="_blank" rel="noreferrer"><code>packages/server/integrations.ts</code></a></td><td>111-127</td></tr><tr><td>Obsidian設定ストレージ</td><td><a href="https://github.com/backnotprop/plannotator/blob/main/packages/ui/utils/obsidian.ts#L36-L43" target="_blank" rel="noreferrer"><code>packages/ui/utils/obsidian.ts</code></a></td><td>36-43</td></tr><tr><td>Settings UIコンポーネント</td><td><a href="https://github.com/backnotprop/plannotator/blob/main/packages/ui/components/Settings.tsx#L387-L491" target="_blank" rel="noreferrer"><code>packages/ui/components/Settings.tsx</code></a></td><td>387-491</td></tr></tbody></table><p><strong>主要な関数</strong>：</p><ul><li><code>detectObsidianVaults()</code>：Obsidian設定ファイルを読み取り、利用可能なvaultパスリストを返す</li><li><code>saveToObsidian(config)</code>：プランを指定vaultに保存、frontmatterとbacklinkを含む</li><li><code>extractTags(markdown)</code>：プラン内容からタグを抽出（タイトルキーワード、コード言語、プロジェクト名）</li><li><code>generateFrontmatter(tags)</code>：YAML frontmatter文字列を生成</li><li><code>generateFilename(markdown)</code>：読みやすいファイル名を生成</li></ul><p><strong>ビジネスルール</strong>：</p><ul><li>タグ数は最大7個（L73）</li><li>ファイル名は50文字制限（L102）</li><li>クロスプラットフォーム設定ファイルパス検出をサポート（L141-149）</li><li>存在しないフォルダを自動作成（L208）</li></ul></details>`,79)])])}const k=t(n,[["render",r]]);export{b as __pageData,k as default};
